func (o *Season) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "EventDriverStandings":
		rels, ok := retrieved.(EventDriverStandingSlice)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.EventDriverStandings = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Season = o
			}
		}
		return nil
	case "EventTeamStandings":
		rels, ok := retrieved.(EventTeamStandingSlice)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.EventTeamStandings = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Season = o
			}
		}
		return nil
	case "Events":
		rels, ok := retrieved.(EventSlice)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.Events = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Season = o
			}
		}
		return nil
	case "SeasonCarClasses":
		rels, ok := retrieved.(SeasonCarClassSlice)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.SeasonCarClasses = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Season = o
			}
		}
		return nil
	case "SeasonDriverStandings":
		rels, ok := retrieved.(SeasonDriverStandingSlice)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.SeasonDriverStandings = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Season = o
			}
		}
		return nil
	case "SeasonTeamStandings":
		rels, ok := retrieved.(SeasonTeamStandingSlice)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.SeasonTeamStandings = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Season = o
			}
		}
		return nil
	case "PointSystem":
		rel, ok := retrieved.(*PointSystem)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.PointSystem = rel

		if rel != nil {
			rel.R.Seasons = SeasonSlice{o}
		}
		return nil
	case "Series":
		rel, ok := retrieved.(*Series)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.Series = rel

		if rel != nil {
			rel.R.Seasons = SeasonSlice{o}
		}
		return nil
	case "Teams":
		rels, ok := retrieved.(TeamSlice)
		if !ok {
			return fmt.Errorf("season cannot load %T as %q", retrieved, name)
		}

		o.R.Teams = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Season = o
			}
		}
		return nil
	default:
		return fmt.Errorf("season has no relationship %q", name)
	}
}

